// filepath: c:\Users\hugov\visualstudio-workspace\task-frontend\src\pages\TasksPage.jsx
import { useState, useEffect, use } from "react";
import TaskList from "../components/TaskList";
import TaskForm from "../components/TaskForm";
import { createTask, deleteTask, getCompletedTasks, getPendingTasks, toggleTaskComplete, updateTask } from "../api/api";
import { groupTasksByDate } from "../utils/groupTasksByDate";
import Card from "../components/Card";
import { motion } from "motion/react";
import { div } from "framer-motion/client";
import { useLocation } from "react-router-dom";

export default function TasksPage() {
    
    const [completed, setCompleted] = useState([]);

    const [grouped, setGrouped] = useState({
        today: [],
        tomorrow: [],
        week: [],
        month: [],
        later: []
    });
    const [drafts, setDrafts] = useState({
        today: false,
        tomorrow: false,
        week: false,
        month: false,
        later: false
    });

    const location = useLocation();
    const [name, setName] = useState(null);
    const [showGreeting, setShowGreeting] = useState(false);


    
    useEffect(() => {

        const tname = location?.state?.name;
        if (tname){
            setName(tname);
            setShowGreeting(true);
            setTimeout(() => {
                setShowGreeting(false);
                loadTasks();
            }, 2000);
            
        }
         loadTasks();  
    }, [])

    function startDraft(group){
        setDrafts(d => ({...d, [group] : true}))
    }

    function cancelDraft(group){
        setDrafts(d => ({...d, [group] : false}))
    }

    function createDraftTask(group){
        const uid = `draft-${group}-${Date.now()}-${Math.floor(Math.random()*1000)}`;
        return{
            id: uid,
            title: "",
            description: "",
            dueDate: "",
            completed: false,
            isDraft: true
        };
    }

    async function loadTasks() {
        const pendingTasks = await getPendingTasks();
        setGrouped(groupTasksByDate(pendingTasks));

        getCompletedTasks().then(setCompleted);
    }

    async function handleCreateTask(task, draftId) {
        const created = await createTask(task);
        if (!created || !created.id) {
            await loadTasks();
            return;
        }
       
        const parts = draftId.split("-");
        let draftGroup = parts.length >= 2 ? parts[1] : undefined;

        if (draftGroup) {
            setGrouped((g) => {
                const list = [...g[draftGroup]];
                list.push(created);
                return { ...g, [draftGroup]: list };
            });
            setDrafts((d) => ({ ...d, [draftGroup]: false }));
        } else {
            await loadTasks();
        }
    }

    async function handleOnToggle(id) {
        await toggleTaskComplete(id);
        loadTasks();
    }

    async function handleOnDelete(id) {
        const ok = window.confirm("¿Estás seguro de que deseas eliminar esta tarea?");
        if (!ok) return;

        // Optimistic update: remove the task locally so the UI shifts smoothly
        setGrouped((g) => {
            const newG = {};
            Object.entries(g).forEach(([key, list]) => {
                newG[key] = list.filter((t) => t.id !== id);
            });
            return newG;
        });
        setCompleted((c) => c.filter((t) => t.id !== id));

        try {
            await deleteTask(id);
        } catch (err) {
            // Revert/fallback: reload from server if deletion failed
            await loadTasks();
        }
    }

    async function handleOnUpdate(id, task) {
        await updateTask(id, task);
        loadTasks();
    }

    if (showGreeting) {
  return (
    <div className="min-h-screen flex items-center justify-center">
      <div className="text-center">
        <h1 className="text-3xl font-bold">Hola {name}</h1>
      </div>
    </div>
  );
}

    return (
        <>


            <div >
                {/* ================== PENDIENTES ================== */}
                <div className="grid w-full gap-6 grid-cols-[repeat(auto-fit,minmax(320px,1fr))]">
                    

                        <motion.div
                            initial={{ opacity: 0, y: -40 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ duration: 0.8, ease: "easeOut" }}

                            className="mb-6 ">
                            <Card title="Hoy">
                                <TaskList
                                    tasks={[
                                        ...grouped.today,
                                        ...(drafts.today ? [createDraftTask("today")] : [])
                                    ]}
                                    onDelete={handleOnDelete}
                                    onCloseDraft={cancelDraft}
                                    onToggle={handleOnToggle}
                                    onUpdate={handleOnUpdate}
                                    onCreate={handleCreateTask}
                                />
                                <div className=" h-5 mt-1">
                                    {!drafts.today && (
                                        <button onClick={() => startDraft("today")} className="text-sm text-[--color-muted] hover:underline opacity-0 pointer-events-none group-hover/card:opacity-100 group-hover/card:pointer-events-auto transition-all duration-200">
                                            añadir tarea
                                        </button>
                                    )}
                                </div>
                            </Card>
                        </motion.div>

                     < motion.div
                            initial={{ opacity: 0, y: -40 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ duration: 0.8, ease: "easeOut" }}>
                        <div className="mb-6">
                            <Card title="Mañana">
                                <TaskList
                                    tasks={[
                                        ...grouped.tomorrow,
                                        ...(drafts.tomorrow ? [createDraftTask("tomorrow")] : [])
                                    ]}                                
                                    onDelete={handleOnDelete}
                                    onCloseDraft={cancelDraft}
                                    onToggle={handleOnToggle}
                                    onUpdate={handleOnUpdate}
                                    onCreate={handleCreateTask}
                                />
                                <div className=" h-5 mt-1">
                                    {!drafts.tomorrow && (
                                        <button onClick={() => startDraft("tomorrow")} className="text-sm text-[--color-muted] hover:underline opacity-0 pointer-events-none group-hover/card:opacity-100 group-hover/card:pointer-events-auto transition-all duration-200">
                                            añadir tarea
                                        </button>
                                    )}
                                </div>                                
                            </Card>
                        </div>
                          </motion.div>

                     < motion.div
                            initial={{ opacity: 0, y: -40 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ duration: 0.8, ease: "easeOut" }}>
                        <div className="mb-6">
                            <Card title="Esta semana">
                                <TaskList
                                    tasks={[
                                        ...grouped.week,
                                        ...(drafts.week ? [createDraftTask("week")] : [])
                                    ]}
                                    onDelete={handleOnDelete}
                                    onCloseDraft={cancelDraft}
                                    onToggle={handleOnToggle}
                                    onUpdate={handleOnUpdate}
                                    onCreate={handleCreateTask}
                                />
                                <div className=" h-5 mt-1">
                                    {!drafts.week && (
                                        <button onClick={() => startDraft("week")} className="text-sm text-[--color-muted] hover:underline opacity-0 pointer-events-none group-hover/card:opacity-100 group-hover/card:pointer-events-auto transition-all duration-200">
                                            añadir tarea
                                        </button>
                                    )}
                                </div>                                
                            </Card>
                        </div>
                    </motion.div>

                     < motion.div
                            initial={{ opacity: 0, y: -40 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ duration: 0.8, ease: "easeOut" }}>
                        <div className="mb-6">
                            <Card title="Este mes">
                                <TaskList
                                    tasks={[
                                        ...grouped.month,
                                        ...(drafts.month ? [createDraftTask("month")] : [])
                                    ]}
                                    onDelete={handleOnDelete}
                                    onCloseDraft={cancelDraft}
                                    onToggle={handleOnToggle}
                                    onUpdate={handleOnUpdate}
                                    onCreate={handleCreateTask}
                                />
                                <div className=" h-5 mt-1">
                                    {!drafts.month && (
                                        <button onClick={() => startDraft("month")} className="text-sm text-[--color-muted] hover:underline opacity-0 pointer-events-none group-hover/card:opacity-100 group-hover/card:pointer-events-auto transition-all duration-200">
                                            añadir tarea
                                        </button>
                                    )}
                                </div>                                
                            </Card>
                        </div>
                        </motion.div>

                        <motion.div
                            initial={{ opacity: 0, y: -40 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ duration: 0.8, ease: "easeOut" }}
                            className="mb-6">
                            <Card title="Sin fecha o más adelante">
                                <TaskList
                                    tasks={[
                                        ...grouped.later,
                                        ...(drafts.later ? [createDraftTask("later")] : [])
                                    ]}
                                    onDelete={handleOnDelete}
                                    onCloseDraft={cancelDraft}
                                    onToggle={handleOnToggle}
                                    onUpdate={handleOnUpdate}
                                    onCreate={handleCreateTask}
                                />
                                <div className=" h-5 mt-1">
                                    {!drafts.later && (
                                        <button onClick={() => startDraft("later")} className="text-sm text-[--color-muted] hover:underline opacity-0 pointer-events-none group-hover/card:opacity-100 group-hover/card:pointer-events-auto transition-all duration-200">
                                            añadir tarea
                                        </button>
                                    )}
                                </div>                                
                            </Card>
                        </motion.div>
                </div>

                {/* ================== COMPLETADAS ================== */}
                <div>
                    <h2>Tareas completadas</h2>

                    {completed.length === 0 ? (
                        <p>No hay tareas completadas</p>
                    ) : (
                        <TaskList
                            onDelete={handleOnDelete}
                            onToggle={handleOnToggle}
                            onUpdate={handleOnUpdate}
                            tasks={completed}
                        />
                    )}
                </div>
                            <h1>Mis tareas</h1>
            <TaskForm onClickButton={handleCreateTask} />
            </div>
        </>
    );
}
