// filepath: c:\Users\hugov\visualstudio-workspace\task-frontend\src\api\api.js
const API_URL = "/api"

export async function getTasks() {
    const response = await fetch(`${API_URL}/tasks`);
    return response.json();
}

export async function getPendingTasks() {
    const response = await fetch(`${API_URL}/tasks?completed=false`);
    return response.json();
}

export async function getCompletedTasks() {
    const response = await fetch(`${API_URL}/tasks?completed=true`);
    return response.json();
}

export async function createTask(task){
    const response = await fetch(`${API_URL}/tasks`, {
        method: "POST",
        headers: {"Content-Type": "application/json"},
        body: JSON.stringify(task)
        }
    )
    return response.json();
}

export async function deleteTask(id){
    const response = await fetch(`${API_URL}/tasks/${id}`, {
        method: "DELETE"
    }
    );
}

export async function updateTask(id, task){
    const response = await fetch (`${API_URL}/tasks/${id}`, {
        method:"PUT",
        headers: {"Content-Type": "application/json"},
        body: JSON.stringify(task)
    }
    );
    return response.json();
}

export async function toggleTaskComplete(id){
    const response = await fetch(`${API_URL}/tasks/${id}/complete`, {
        method: "PATCH"
    }
    );
    return response.json();
}
