// filepath: c:\Users\hugov\visualstudio-workspace\task-frontend\src\components\TaskList.jsx
import TaskItem from "./TaskItem";
import { motion, AnimatePresence } from "framer-motion";

export default function TaskList({ tasks, ...handlers }) {
  return (
    <div className="flex flex-col gap-3">
      <AnimatePresence initial={false} mode="popLayout">
        {tasks.map((task) => {
          const layoutId = task.id;
          const initial = { opacity: 0, y: -16 };
          const exit = { opacity: 0, y: 16 };
          const transition = { type: "spring", stiffness: 320, damping: 28 };

          return (
            <motion.div
              key={task.id}
              layout
              layoutId={layoutId}
              initial={initial}
              animate={{ opacity: 1, y: 0 }}
              exit={exit}
              transition={transition}
            >
              <TaskItem task={task} {...handlers} />
            </motion.div>
          );
        })}
      </AnimatePresence>
    </div>
  );
}
