// filepath: c:\Users\hugov\visualstudio-workspace\task-frontend\src\components\TaskItem.jsx
import { useState } from "react";
import { motion } from "motion/react";
import FancyButton from "./FancyButton";
import { div } from "framer-motion/client";

export default function TaskItem({ task, onToggle, onUpdate, onDelete, onCreate, onCloseDraft }) {
  const [editing, setEditing] = useState(task.isDraft || false);
  const [title, setTitle] = useState(task.title);
  const [description, setDescription] = useState(task.description);
  const [dueDate, setDueDate] = useState(task.dueDate);

  async function save() {
    if (title.trim() === "") return;
    if (task.isDraft) {
      await onCreate({ title: title, description: description, dueDate: dueDate, priority: "MEDIUM" }, task.id);
    } else {
      await onUpdate(task.id, { ...task, title, description, dueDate });
      setEditing(false);
    }
  }

  function cancel() {
    if(task.isDraft) {
      setTitle("")
      setDescription("")
      setDueDate("")
      onCloseDraft("today");
     
    }else{
    setTitle(task.title);
    setDescription(task.description);
    setDueDate(task.dueDate)
    setEditing(false);
    }
  }


  return (
<div className="relative group w-full">
  {/* borde desplazado (fondo) */}
  <span className="pointer-events-none absolute inset-0 rounded-xl bg-cardback" />
    
    <div
    
     
      className="
        bg-card
        border border-gray-400
        rounded-xl
        p-4
        flex
        gap-4
        group/taskItem
        
   


              relative  px-6 py-4
      shadow-md
      transition-all duration-150 ease-out
      hover:-translate-x-1 hover:-translate-y-1
      hover:shadow-sm
    
      "
    >
      
      {/* BOTONES */}
      <div className="flex flex-col gap-3 shrink-0">
        {/* EDITAR */}
        {!editing && (
          <>
            <FancyButton color="green" onClick={() => onToggle(task.id)} className="w-24" >
              completar
            </FancyButton>
            <FancyButton color="yellow" onClick={() => setEditing(true)} className="w-24" >
              editar
            </FancyButton>
          </>

        )}
      </div>

      {/* CONTENIDO */}
      <div className="flex-1 min-w-0">
        {editing ? (
          <div className="flex flex-col">
            <input
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              autoFocus
              className="
                w-full
                bg-transparent
                border border-[--color-border]
                rounded-md
                px-2 py-1
                mb-2
              "
            />

            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              rows={3}
              placeholder="Detalles"
              className="
                w-full
                bg-transparent
                border border-[--color-border]
                rounded-md
                px-2 py-1
                resize-none
                max-h-40
                overflow-auto
                mb-2
              "
            />
            
            <div className="flex items-center gap-3 mb-2">
              <label className="text-sm text-[--color-muted]">Fecha</label>
              <input
                type="date"
                value={dueDate || ""}
                onChange={(e) => setDueDate(e.target.value)}
                className="bg-transparent border border-[--color-border] rounded-md px-2 py-1"
              />
            </div>

            <div className="flex gap-2 mt-auto">
              <FancyButton onClick={save} color="green" disabled={title.trim() === ""}>guardar</FancyButton>
              <FancyButton onClick={cancel} color="red2">cancelar</FancyButton>
            </div>
          </div>
        ) : (
          <>
            <p
              className={`font-medium break-words [overflow-wrap:anywhere]${task.completed
                  ? "line-through text-[--color-muted]"
                  : ""
                }`}
            >
              {task.title}
            </p>

            {task.description && (
              <p className="text-sm text-[--color-muted] mt-1">
                {task.description}
              </p>
            )}

            <p className="text-xs text-[--color-muted] mt-2">
              {task.dueDate ? `⏰ ${task.dueDate}` : "⏰ Sin fecha límite"}
            </p>
          </>
        )}
      </div>
{!editing && (
  <div className="absolute top-19 right-4 z-20">
    <FancyButton
      color="red"
      onClick={() => onDelete(task.id)}
      className="    px-2.5
    py-2.5
    text-base
    leading-none
  "
    >
      ✕
    </FancyButton>
  </div>
)}
    </div>
    {/* ELIMINAR */}
{/* ELIMINAR */}



    </div>
  );
}
