    public TaskResponseDTO create(TaskRequestDTO dto) {
        Task task = taskMapper.toEntity(dto);
        return taskMapper.toResponse(repository.save(task));
    }
    
    public List<TaskResponseDTO> findAll(Boolean completed){
        
        if(completed != null) {
            return repository.findByCompleted(completed).stream().map(task -> taskMapper.toResponse(task)).toList();
        } else {
            return repository.findAll().stream().map(task -> taskMapper.toResponse(task)).toList();
        }
    }
    
    public TaskResponseDTO findById(Long id) {
        return taskMapper.toResponse(repository.findById(id).orElseThrow(() -> new ResourceNotFoundException("Task " + id +  " not found"))); 
    }
    
    public TaskResponseDTO update(Long id, TaskRequestDTO dto) {
        Task task = repository.findById(id).orElseThrow(() -> new ResourceNotFoundException("Task " + id +  " not found")); 
        
        taskMapper.updateEntityFromDto(dto, task);

        return taskMapper.toResponse(repository.save(task));
    }
    
    public TaskResponseDTO toggleComplete(Long id) {
        Task task = repository.findById(id).orElseThrow(() -> new ResourceNotFoundException("Task " + id +  " not found"));
        task.setCompleted(!task.isCompleted());
        return taskMapper.toResponse(repository.save(task));
    }
    
    
    
    public void delete(Long id) {
        repository.deleteById(id);
    }
}
