package com.example.task.controller;

import java.util.List;

import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.DeleteMapping;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PatchMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.PutMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import com.example.task.dto.TaskRequestDTO;
import com.example.task.dto.TaskResponseDTO;
import com.example.task.model.Task;
import com.example.task.service.TaskService;

import jakarta.validation.Valid;

@RestController
@RequestMapping("/api/tasks")
public class TaskController {

    
    private final TaskService service;
    
    public TaskController(TaskService service) {
        this.service = service;
    }
    
    @PostMapping
    public ResponseEntity<TaskResponseDTO> create( @Valid @RequestBody TaskRequestDTO task){
        return ResponseEntity.status(HttpStatus.CREATED).body(service.create(task));
    }
    
    
    @GetMapping
    public List<TaskResponseDTO> findAll( @RequestParam(required = false) Boolean completed ){
        return service.findAll(completed);
    }
    
    @GetMapping("/{id}")
    public TaskResponseDTO findById(@PathVariable Long id) {
        return service.findById(id);
    }
    
    @PutMapping("/{id}")
    public TaskResponseDTO update(@PathVariable Long id, @Valid @RequestBody TaskRequestDTO dto) {
        return service.update(id, dto);
    }
    
    @PatchMapping("/{id}/complete")
    public TaskResponseDTO toggleComplete(@PathVariable Long id) {
        return service.toggleComplete(id);
    }
    
    
    @DeleteMapping("/{id}")
    public ResponseEntity<Void> delete(@PathVariable Long id){
        service.delete(id);
        return ResponseEntity.noContent().build();
    }
}
