import keycloak from "../auth/keycloak";

const API_URL = "/api";

async function authFetch(path, options = {}) {
  const headers = new Headers(options.headers || {});
  headers.set("Content-Type", "application/json");

  if (keycloak?.token) {
    headers.set("Authorization", `Bearer ${keycloak.token}`);
  }

  const response = await fetch(`${API_URL}${path}`, { ...options, headers });

  // opcional: si te expira, fuerza relogin
  if (response.status === 401) {
    // puedes intentar refresh antes, pero con el setInterval suele bastar
  }

  return response;
}

export async function getPendingTasks() {
  const r = await authFetch("/tasks?completed=false");
  return r.json();
}

// y lo mismo para el resto (getCompletedTasks, createTask, etc.)
